SELECT 
FROM turtle_soup_stories s
WHERE s.active = 1

    AND s.id NOT IN

        #{id}


  AND NOT EXISTS (
      SELECT 1
      FROM turtle_soup_records r
      WHERE r.story_id = s.id
        AND (
            r.host_key = #{playerAKey}
            OR r.guesser_key = #{playerAKey}
            OR r.host_key = #{playerBKey}
            OR r.guesser_key = #{playerBKey}
        )
  )
ORDER BY RANDOM()
LIMIT 1

